var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"합중국, 브라이트 포트 봉쇄지구 – 20:07:38\\n스캐빈저, 강습함 <color=#ffd34c>마타도르</color>\\nCSE Level <b>2+</b>","JPN":"合衆国、ブライトポート封鎖地区　–　20:07:38\\nスカベンジャー、強襲艦<color=#ffd34c>マタドール</color>\\nCSE Level<b>2+</b>","ENG":"The States, Bright Port Sealed Area – 20:07:38\\nScavengers, Assault Ship <color=#ffd34c>Matador</color>\\nCSE Level <b>2+</b>","TWN":"合眾國 布萊特港封鎖地區 – 20:07:38\\n清道夫，強襲艦 <color=#ffd34c>鬥牛士</color>\\nCSE Level <b>2+</b>","THA":"อเมริกา พื้นที่หวงห้ามท่าเรือไบรต์ – 20:07:38\\nสคาเวนเจอร์ ยานรบจู่โจม <color=#ffd34c>มาทาดอร์</color>\\nระดับ CSE <b>2+</b>","VTN":"Hoa Kỳ, Khu Vực Bị Phong Ấn Cảng Bright - 20:07:38 \\nThe Scavengers, Tàu Đột Kích <color=#ffd34c>Matador</color>\\nCấp CSE <b>2+</b>","SCN":"联邦，布莱特福特封锁地区 - 20：07：38\\n清道夫强袭战舰 <color=#ffd34c>斗牛士</color>\\nCSE Level <b>2+</b>","DEU":"USA, Versiegelter Bereich Bright Port – 20:07:38\\nScavenger, Sturmschiff <color=#ffd34c>Matador</color>\\nCSE-Stufe: <b>2+</b>","FRA":"États-Unis, zone interdite de Port Bright\xA0–\xA020:07:38\\nVaisseau d'assaut des Scavengers, <color=#ffd34c>Matador</color>\\nNiveau d'ECM <b>2+</b>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"오, 남의 집 쓰레기통을 뒤지는 일은 정말이지 적성에 안 맞아.","JPN":"ああ、他所んちのゴミ箱を漁るなんて本当に性に合わねえぜ。","ENG":"Oh, how I hate to go through someone else’s trash.","TWN":"吼唷，翻別人家的垃圾桶根本不是我會做的事。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"리플레이서인지 뭔지 이미 폭삭 망했다며? 우린 왜 쉴 틈도 없이 여기서 뺑이를 치는 거야?","JPN":"リプレイサーとやらは完全に滅びたんだろ？　なんで俺らは休む間もなく、ここで雑用係をさせられるわけ？","ENG":"The Replacers are all gone now, right? Then why do we have to work our butt off here?","TWN":"克隆集團還什麼的，不是已經完蛋了嗎？為什麼我們還在這裡幹這種苦差事？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>리액터</color>를 찾아오라는 두목의 명령이다.","JPN":"<color=#ffd34c>リアクター</color>を探してこいというのがボスの命令だ。","ENG":"The boss wants us to find the <color=#ffd34c>reactor</color>.","TWN":"老大要我們來找<color=#ffd34c>反應爐</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그리고 스캐빈저는 제일 센 놈이 대장이지. 불만이 있으면 두목에게 가서 말해.","JPN":"それに、スカベンジャーは一番強い奴が隊長だろ？　文句があるならボスに直接言え。","ENG":"And you know the strongest rules among us Scavengers. So if you have a problem, go talk to the boss.","TWN":"而且在清道夫裡，最強的人就是隊長！你有什麼意見的話，自己去找老大說。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"히히, 두목이랑 붙으면 나 응원해 줄 거야?","JPN":"ひひっ、ボスとやることになったら俺を応援してくれるか？","ENG":"Hehe, if I fight her, will you be on my side?","TWN":"嘿嘿，我跟老大打起來的話，你替我加油嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"시체는 수습해 주지. 네 몸뚱이에는 쓸 만한 부품들이 들어가 있으니까.","JPN":"まあ、死体は引き取ってやる。\\nお前の体には使えそうな部品が入っているからな。","ENG":"I will take care of your dead body. You'll probably have some useful parts left.","TWN":"我會替你收屍，畢竟你身上還有一些能用的零件。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"멀쩡하게 건질 수 있을지는 모르겠지만.","JPN":"使える状態で残っているかはわからないがな。","ENG":"Though I’m not sure if they'll be in good enough shape to be worth it.","TWN":"只是不確定老大會留你全屍嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"이런, 네가 내 몸에 눈독 들이고 있는 줄은 상상도 못했네.","JPN":"おっと、お前が俺の体に興味があったなんて想像もしてなかったぜ。","ENG":"Oh, I didn’t know you were interested in my body.","TWN":"沒想到你這傢伙竟然覬覦我的身體！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"어때, 수확은 좀 있나?","JPN":"どうだ、収穫はあったか？","ENG":"How is it going?","TWN":"如何？有什麼收穫嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"오, 잘 왔어. 세뇨라. 안 그래도 부르러 갈 생각이었거든.","JPN":"おっ、いいところに来たなセニョーラ。ちょうど呼びにいくとこだったんだ。","ENG":"Hola, señorita. I was about to call you.","TWN":"喔，你來啦，Senora！正想去找老大呢！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"그 리액터라는 거 말이야, 정말 여기 있는 게 확실해?","JPN":"そのリアクターとやら、本当にここにあるのか？","ENG":"That reactor, is it really here?","TWN":"那個反應爐真的在這裡嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"우리 잘나신 의장 나리가 준 정보니 가능성이 있다고 봐야지.","JPN":"うちの立派な議長様からの情報だから、その可能性は高いだろう。","ENG":"The information is from our glorious chairman, so it’s highly likely.","TWN":"是我們偉大的議長大人說的，應該有點可信度吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"뭔 생각을 하는지 모를 녀석이긴 하지만 정보력만큼은 마스터도 인정하니까.","JPN":"腹の内はわからないが、情報収集力だけはマスターも認めたからな。","ENG":"I don’t know what’s on his mind, but even the Master respects his intel.","TWN":"雖然不知道他腦袋裡在想什麼，不過他的情報能力可是連主人也認可的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"가능성이래. 우리 엄마도 나더러 넌 커서 크게 될 가능성이 있다고 했지, 아마.","JPN":"可能性かよ。うちの母ちゃんも､俺が大人になったら\\nビッグになる可能性があるって言ってたぜ､たしか｡","ENG":"Quite so. My mom told me that I was likely to become a big shot when I grow up.","TWN":"可信度嗎？當初我媽說我長大後一定大有可為，我也覺得有點可信度。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};